  function durationToHours(value){if(value===null||value===undefined)return 0;if(typeof value==='number'){if(value>86400000)return value/3600000;if(value>10000)return value/1000/3600;return value/3600;}if(typeof value==='string'){var iso=value.match(/P(?:\d+D)?T(?:(\d+)H)?(?:(\d+)M)?(?:(\d+(?:\.\d+)?)S)?/i);if(iso)return toNum(iso[1])+toNum(iso[2])/60+toNum(iso[3])/3600;var parts=value.split(':');if(parts.length===3)return toNum(parts[0])+toNum(parts[1])/60+toNum(parts[2])/3600;var numeric=Number(value);if(!isNaN(numeric))return durationToHours(numeric);}if(typeof value==='object'){if(value.ticks!==undefined)return toNum(value.ticks)/10000000/3600;if(value.TotalHours!==undefined)return toNum(value.TotalHours);if(value.totalHours!==undefined)return toNum(value.totalHours);if(value.hours!==undefined||value.minutes!==undefined||value.seconds!==undefined)return toNum(value.hours)+toNum(value.minutes)/60+toNum(value.seconds)/3600;}return 0;}
